param(
    [string]$ConfigPath = (Join-Path (Split-Path -Parent $PSScriptRoot) "config.json")
)

Set-StrictMode -Version Latest
$ErrorActionPreference = "Stop"
$script:LogPath = $null

function Write-Log {
    param([string]$Message, [string]$Level = "INFO")
    $line = "[{0}] [{1}] {2}" -f (Get-Date -Format "yyyy-MM-dd HH:mm:ss"), $Level, $Message
    if (-not [string]::IsNullOrWhiteSpace($script:LogPath)) {
        Add-Content -Path $script:LogPath -Value $line -Encoding UTF8
    }
    Write-Host $line
}
function Get-ConfigValue { param($Config,[string]$Name,$DefaultValue) if($null -ne $Config.PSObject.Properties[$Name] -and $null -ne $Config.$Name){return $Config.$Name}; return $DefaultValue }
function HtmlEncode { param([AllowNull()][string]$Text) if($null -eq $Text){return ""}; return [System.Net.WebUtility]::HtmlEncode($Text) }
function ConvertTo-SafeJson { param($Value) $json=ConvertTo-Json -InputObject $Value -Depth 12 -Compress; if([string]::IsNullOrWhiteSpace($json)){return "{}"}; return ($json -replace '</','<\/') }
function New-DateOnly { param([int]$Year,[int]$Month,[int]$Day) return (Get-Date -Year $Year -Month $Month -Day $Day -Hour 0 -Minute 0 -Second 0) }
function Add-Holiday { param([hashtable]$Map,[datetime]$Date,[string]$Name) $Map[$Date.ToString("yyyy-MM-dd")]=$Name }
function Get-NthMonday { param([int]$Year,[int]$Month,[int]$Nth) $d=New-DateOnly $Year $Month 1; while($d.DayOfWeek -ne [DayOfWeek]::Monday){$d=$d.AddDays(1)}; return $d.AddDays(7*($Nth-1)) }
function Get-VernalDay { param([int]$Year) return [int][Math]::Floor(20.8431 + 0.242194 * ($Year - 1980) - [Math]::Floor(($Year - 1980) / 4)) }
function Get-AutumnalDay { param([int]$Year) return [int][Math]::Floor(23.2488 + 0.242194 * ($Year - 1980) - [Math]::Floor(($Year - 1980) / 4)) }
function Add-GenericJapaneseHolidays { param([hashtable]$Map,[int]$Year)
    Add-Holiday $Map (New-DateOnly $Year 1 1) "元日"; Add-Holiday $Map (Get-NthMonday $Year 1 2) "成人の日"; Add-Holiday $Map (New-DateOnly $Year 2 11) "建国記念の日"; Add-Holiday $Map (New-DateOnly $Year 2 23) "天皇誕生日"; Add-Holiday $Map (New-DateOnly $Year 3 (Get-VernalDay $Year)) "春分の日"; Add-Holiday $Map (New-DateOnly $Year 4 29) "昭和の日"; Add-Holiday $Map (New-DateOnly $Year 5 3) "憲法記念日"; Add-Holiday $Map (New-DateOnly $Year 5 4) "みどりの日"; Add-Holiday $Map (New-DateOnly $Year 5 5) "こどもの日"; Add-Holiday $Map (Get-NthMonday $Year 7 3) "海の日"; Add-Holiday $Map (New-DateOnly $Year 8 11) "山の日"; Add-Holiday $Map (Get-NthMonday $Year 9 3) "敬老の日"; Add-Holiday $Map (New-DateOnly $Year 9 (Get-AutumnalDay $Year)) "秋分の日"; Add-Holiday $Map (Get-NthMonday $Year 10 2) "スポーツの日"; Add-Holiday $Map (New-DateOnly $Year 11 3) "文化の日"; Add-Holiday $Map (New-DateOnly $Year 11 23) "勤労感謝の日"
}
function Add-Official2026And2027Holidays { param([hashtable]$Map)
    $items=@(@('2026-01-01','元日'),@('2026-01-12','成人の日'),@('2026-02-11','建国記念の日'),@('2026-02-23','天皇誕生日'),@('2026-03-20','春分の日'),@('2026-04-29','昭和の日'),@('2026-05-03','憲法記念日'),@('2026-05-04','みどりの日'),@('2026-05-05','こどもの日'),@('2026-05-06','休日'),@('2026-07-20','海の日'),@('2026-08-11','山の日'),@('2026-09-21','敬老の日'),@('2026-09-22','休日'),@('2026-09-23','秋分の日'),@('2026-10-12','スポーツの日'),@('2026-11-03','文化の日'),@('2026-11-23','勤労感謝の日'),@('2027-01-01','元日'),@('2027-01-11','成人の日'),@('2027-02-11','建国記念の日'),@('2027-02-23','天皇誕生日'),@('2027-03-21','春分の日'),@('2027-03-22','休日'),@('2027-04-29','昭和の日'),@('2027-05-03','憲法記念日'),@('2027-05-04','みどりの日'),@('2027-05-05','こどもの日'),@('2027-07-19','海の日'),@('2027-08-11','山の日'),@('2027-09-20','敬老の日'),@('2027-09-23','秋分の日'),@('2027-10-11','スポーツの日'),@('2027-11-03','文化の日'),@('2027-11-23','勤労感謝の日'))
    foreach($i in $items){$Map[$i[0]]=$i[1]}
}
function Add-SubstituteAndCitizenHolidays { param([hashtable]$Map,[int]$Year)
    $start=New-DateOnly $Year 1 1; $end=New-DateOnly $Year 12 31; $keys=@($Map.Keys|Where-Object{$_ -like ("{0}-*" -f $Year)}|Sort-Object)
    foreach($key in $keys){$d=[datetime]::ParseExact($key,'yyyy-MM-dd',$null); if($d.DayOfWeek -eq [DayOfWeek]::Sunday){$sub=$d.AddDays(1); while($sub -le $end -and $Map.ContainsKey($sub.ToString('yyyy-MM-dd'))){$sub=$sub.AddDays(1)}; if($sub -le $end){$Map[$sub.ToString('yyyy-MM-dd')]='休日'}}}
    $d2=$start.AddDays(1); while($d2 -lt $end){$prev=$d2.AddDays(-1).ToString('yyyy-MM-dd');$cur=$d2.ToString('yyyy-MM-dd');$next=$d2.AddDays(1).ToString('yyyy-MM-dd'); if(-not $Map.ContainsKey($cur) -and $Map.ContainsKey($prev) -and $Map.ContainsKey($next)){$Map[$cur]='休日'}; $d2=$d2.AddDays(1)}
}
function Get-HolidayMap { param($Config,[datetime]$RangeStart,[datetime]$RangeEnd)
    $map=@{}; for($year=$RangeStart.Year-1;$year -le $RangeEnd.Year+1;$year++){Add-GenericJapaneseHolidays $map $year; Add-SubstituteAndCitizenHolidays $map $year}; Add-Official2026And2027Holidays $map
    $extra=Get-ConfigValue $Config 'HolidayDates' @(); foreach($entry in @($extra)){ if($entry -is [string]){$map[[string]$entry]='祝日'} else {$date=if($null -ne $entry.PSObject.Properties['Date']){[string]$entry.Date}else{''}; $name=if($null -ne $entry.PSObject.Properties['Name']){[string]$entry.Name}else{'祝日'}; if(-not [string]::IsNullOrWhiteSpace($date)){$map[$date]=$name}} }
    return $map
}
function Get-ScheduleDataJson { param([string]$Html)
    $pattern='<script id="schedule-data" type="application/json">(?<json>.*?)</script>'
    $m=[regex]::Match($Html,$pattern,[System.Text.RegularExpressions.RegexOptions]::Singleline)
    if(-not $m.Success){ throw 'Could not find schedule-data JSON in generated HTML.' }
    return $m.Groups['json'].Value.Trim()
}
function New-ProHtml { param([string]$Title,[string]$UpdatedText,[string]$DataJson,[string]$HolidayJson)
$template=@'
<!doctype html><html lang="ja"><head><meta charset="utf-8"><title>__TITLE__</title><meta name="viewport" content="width=device-width,initial-scale=1"><style>:root{--bg:#f3f5f9;--card:#fff;--text:#172033;--muted:#64748b;--line:#e5e7eb;--accent:#2563eb;--soft:#e8f0ff;--todayLine:#fb923c;--selected:#eef4ff;--private:#f5f5f5;--sat:#eff6ff;--sun:#fff1f2;--holiday:#fff7ed;--shadow:0 18px 42px rgba(15,23,42,.09)}*{box-sizing:border-box}body{margin:0;font-family:system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;background:linear-gradient(180deg,#f8fbff 0%,var(--bg) 220px);color:var(--text)}.header{position:sticky;top:0;z-index:20;background:rgba(248,251,255,.9);backdrop-filter:blur(14px);border-bottom:1px solid rgba(229,231,235,.9)}.wrap{max-width:1280px;margin:auto;padding:18px 20px}h1{margin:0;font-size:28px}.meta{margin-top:6px;color:var(--muted);font-size:13px}.summary{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:12px;margin-top:16px}.summary-card,.panel,.event-card,.empty{background:var(--card);border:1px solid rgba(229,231,235,.95);border-radius:18px;box-shadow:var(--shadow)}.summary-card{padding:13px 15px}.summary-label{font-size:12px;color:var(--muted)}.summary-value{font-size:20px;font-weight:850;margin-top:5px}.summary-sub{font-size:12px;color:var(--muted);margin-top:4px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.toolbar{display:flex;gap:10px;flex-wrap:wrap;margin-top:14px;align-items:center}.search{flex:1;min-width:260px;position:relative}.search input{width:100%;border:1px solid var(--line);border-radius:999px;padding:11px 14px 11px 40px;font:inherit;background:#fff}.search span{position:absolute;left:14px;top:50%;transform:translateY(-50%);color:var(--muted)}button{border:1px solid var(--line);border-radius:999px;background:#fff;padding:9px 13px;cursor:pointer;font:inherit}button.active,button.primary{border-color:#bfdbfe;background:var(--soft);color:#1d4ed8;font-weight:750}button.primary{background:var(--accent);border-color:var(--accent);color:white}.owner-filter{display:flex;gap:8px;flex-wrap:wrap;margin-top:10px}.owner-filter button{font-size:13px;padding:7px 10px}.layout{max-width:1280px;margin:auto;padding:18px 20px;display:grid;grid-template-columns:minmax(0,1.25fr) minmax(370px,.9fr);gap:18px;align-items:start}.panel{padding:16px}.panel-head{display:flex;justify-content:space-between;align-items:center;gap:12px;margin-bottom:12px}.panel-title{font-size:18px;font-weight:850}.panel-sub{font-size:12px;color:var(--muted);margin-top:3px}.nav{display:flex;gap:8px;align-items:center}.range-label{min-width:150px;text-align:center;font-weight:800}.weekdays,.grid{display:grid;grid-template-columns:repeat(7,minmax(0,1fr));gap:8px}.weekday{font-size:12px;color:var(--muted);font-weight:800;text-align:center;padding:7px 2px}.weekday.sun{color:#dc2626}.weekday.sat{color:#2563eb}.day{min-height:112px;border:1px solid var(--line);border-radius:16px;background:#fff;padding:9px;display:flex;flex-direction:column;gap:7px;cursor:pointer;transition:.12s}.view-week .day{min-height:300px}.day:hover{transform:translateY(-1px);box-shadow:0 10px 24px rgba(15,23,42,.07)}.day.other{opacity:.45;background:#fafafa}.day.sat{background:var(--sat)}.day.sun{background:var(--sun)}.day.holiday{background:var(--holiday);border-color:#fed7aa}.day.today{outline:2px solid var(--todayLine);outline-offset:1px}.day.selected{background:var(--selected);border-color:#8eb3ff;box-shadow:0 12px 30px rgba(37,99,235,.15)}.day-top{display:flex;justify-content:space-between;gap:8px;align-items:flex-start}.date-main{font-weight:850}.holiday-name{display:block;margin-top:2px;font-size:10px;color:#b45309;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.count{min-width:24px;padding:2px 7px;border-radius:999px;background:#eff6ff;color:#1d4ed8;font-size:11px;text-align:center;font-weight:800}.mini-list{margin-top:auto;display:flex;flex-direction:column;gap:4px}.mini{font-size:11px;color:#334155;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;border-left:3px solid var(--accent);padding-left:5px}.mini.private{border-color:#9ca3af;color:#64748b}.more{font-size:11px;color:var(--muted)}.agenda-head{margin-bottom:12px}.agenda-title{font-size:22px;font-weight:850}.agenda-sub{font-size:13px;color:var(--muted);margin-top:4px}.agenda-list{display:flex;flex-direction:column;gap:12px}.event-card{padding:14px;cursor:pointer}.event-card:hover{border-color:#bfdbfe}.event-card.private{background:var(--private)}.event-top{display:flex;justify-content:space-between;gap:12px}.event-title{font-weight:850;line-height:1.4}.event-time{font-weight:850;color:#1d4ed8;white-space:nowrap}.event-meta{font-size:13px;color:var(--muted);margin-top:8px;display:flex;gap:8px;flex-wrap:wrap}.chips{display:flex;gap:7px;flex-wrap:wrap;margin-top:10px}.chip{font-size:12px;border:1px solid var(--line);border-radius:999px;background:#fff;color:var(--muted);padding:3px 8px}.chip.owner{background:#eef4ff;border-color:#bfdbfe;color:#1d4ed8}.chip.warn{background:#fef3c7;border-color:#fde68a;color:#92400e}.empty{padding:28px;color:var(--muted);text-align:center}.modal-bg{position:fixed;inset:0;background:rgba(15,23,42,.38);z-index:50;display:none}.modal{position:fixed;right:22px;top:22px;bottom:22px;width:min(620px,calc(100vw - 44px));background:#fff;border:1px solid var(--line);border-radius:22px;box-shadow:0 24px 70px rgba(15,23,42,.24);z-index:60;display:none;overflow:hidden}.modal.on,.modal-bg.on{display:block}.modal.on{display:flex;flex-direction:column}.modal-head{padding:18px;border-bottom:1px solid var(--line);display:flex;justify-content:space-between;gap:12px}.modal-title{font-size:19px;font-weight:850;line-height:1.4}.modal-hint{font-size:12px;color:var(--muted);margin-top:6px}.modal-body{padding:18px;overflow:auto}.kv{margin:0}.kv dt{font-size:12px;color:var(--muted);font-weight:800;margin-bottom:4px}.kv dd{margin:0 0 14px;white-space:pre-wrap;line-height:1.55}.legend{display:flex;gap:12px;flex-wrap:wrap;margin-top:12px;font-size:12px;color:var(--muted)}.legend span{display:inline-flex;align-items:center;gap:6px}.legend i{width:10px;height:10px;border-radius:3px;display:inline-block;border:1px solid var(--line)}.legend .sat{background:var(--sat)}.legend .sun{background:var(--sun)}.legend .hol{background:var(--holiday)}@media(max-width:980px){.summary{grid-template-columns:repeat(2,minmax(0,1fr))}.layout{grid-template-columns:1fr}.view-week .day{min-height:170px}}@media(max-width:640px){.wrap,.layout{padding:14px}.summary{grid-template-columns:1fr}.day{min-height:82px}.view-week .day{min-height:120px}.modal{left:8px;right:8px;top:auto;bottom:8px;width:auto;max-height:88vh}}@media print{.header{position:static;background:#fff}.toolbar,.owner-filter,.nav button,.modal,.modal-bg{display:none!important}body{background:#fff}.layout{display:block}.panel,.summary-card,.event-card{box-shadow:none}}</style></head><body><div class="header"><div class="wrap"><h1>__TITLE__</h1><div class="meta">Last updated: __UPDATED__</div><div class="summary"><div class="summary-card"><div class="summary-label">今日</div><div id="todayCount" class="summary-value">-</div><div id="todaySub" class="summary-sub">-</div></div><div class="summary-card"><div class="summary-label">選択日</div><div id="selectedCount" class="summary-value">-</div><div id="selectedSub" class="summary-sub">-</div></div><div class="summary-card"><div class="summary-label">表示対象</div><div id="totalCount" class="summary-value">-</div><div class="summary-sub">フィルター・検索反映</div></div><div class="summary-card"><div class="summary-label">次の予定</div><div id="nextEvent" class="summary-value">-</div><div id="nextEventSub" class="summary-sub">-</div></div></div><div class="toolbar"><div class="search"><span>🔎</span><input id="search" type="search" placeholder="件名・場所・主催者・参加者・本文を検索"></div><button id="btnMonth" class="active">月表示</button><button id="btnWeek">週表示</button><button id="btnToday" class="primary">今日へ</button><button id="btnClear">検索クリア</button><button id="btnPrint">印刷</button></div><div id="ownerFilter" class="owner-filter"></div></div></div><main id="layout" class="layout"><section class="panel"><div class="panel-head"><div><div class="panel-title">カレンダー</div><div id="panelSub" class="panel-sub">月表示</div></div><div class="nav"><button id="btnPrev">◀</button><div id="rangeLabel" class="range-label">-</div><button id="btnNext">▶</button></div></div><div class="weekdays"><div class="weekday sun">日</div><div class="weekday">月</div><div class="weekday">火</div><div class="weekday">水</div><div class="weekday">木</div><div class="weekday">金</div><div class="weekday sat">土</div></div><div id="grid" class="grid"></div><div class="legend"><span><i class="sat"></i>土曜</span><span><i class="sun"></i>日曜</span><span><i class="hol"></i>祝日・休日</span></div></section><section class="panel"><div class="agenda-head"><div id="agendaTitle" class="agenda-title">-</div><div id="agendaSub" class="agenda-sub">-</div></div><div id="agendaList" class="agenda-list"></div></section></main><div id="modalBg" class="modal-bg"></div><aside id="modal" class="modal"><div class="modal-head"><div><div id="modalTitle" class="modal-title"></div><div id="modalHint" class="modal-hint"></div></div><button id="btnClose">閉じる</button></div><div id="modalBody" class="modal-body"></div></aside><script id="schedule-data" type="application/json">__DATA__</script><script id="holiday-data" type="application/json">__HOLIDAYS__</script><script>const events=JSON.parse(document.getElementById('schedule-data').textContent||'[]');const holidays=JSON.parse(document.getElementById('holiday-data').textContent||'{}');const search=document.getElementById('search'),ownerFilter=document.getElementById('ownerFilter'),grid=document.getElementById('grid'),rangeLabel=document.getElementById('rangeLabel'),agendaTitle=document.getElementById('agendaTitle'),agendaSub=document.getElementById('agendaSub'),agendaList=document.getElementById('agendaList'),layout=document.getElementById('layout'),modal=document.getElementById('modal'),modalBg=document.getElementById('modalBg');let view='month',owner='all';function pad(n){return String(n).padStart(2,'0')}function todayStr(){const d=new Date();return d.getFullYear()+'-'+pad(d.getMonth()+1)+'-'+pad(d.getDate())}function dObj(s){return new Date(s+'T00:00:00')}function ymd(d){return d.getFullYear()+'-'+pad(d.getMonth()+1)+'-'+pad(d.getDate())}function startMonth(d){return new Date(d.getFullYear(),d.getMonth(),1)}function startWeek(d){const x=new Date(d);x.setDate(x.getDate()-x.getDay());return x}function addDays(d,n){const x=new Date(d);x.setDate(x.getDate()+n);return x}function addMonths(d,n){return new Date(d.getFullYear(),d.getMonth()+n,1)}function fmtDate(s){return new Intl.DateTimeFormat('ja-JP',{year:'numeric',month:'long',day:'numeric',weekday:'short'}).format(dObj(s))}function fmtMonth(d){return new Intl.DateTimeFormat('ja-JP',{year:'numeric',month:'long'}).format(d)}function node(t,c,x){const e=document.createElement(t);if(c)e.className=c;if(x!==undefined&&x!==null)e.textContent=x;return e}const sorted=events.slice().sort((a,b)=>new Date(a.startISO)-new Date(b.startISO));const initial=(sorted.find(e=>e.date===todayStr())||sorted[0]||{date:todayStr()}).date;let selected=initial,anchor=startMonth(dObj(initial));function owners(){const m=new Map();sorted.forEach(e=>{const k=e.calendarKey||'default';if(!m.has(k))m.set(k,{key:k,name:e.calendarName||'予定表',count:0});m.get(k).count++});return Array.from(m.values()).sort((a,b)=>a.name.localeCompare(b.name,'ja'))}function drawOwners(){ownerFilter.innerHTML='';const all=node('button','','全員 ('+sorted.length+')');all.onclick=()=>{owner='all';drawOwners();renderAll()};ownerFilter.appendChild(all);owners().forEach(o=>{const b=node('button','',o.name+' ('+o.count+')');b.onclick=()=>{owner=o.key;drawOwners();renderAll()};b.classList.toggle('active',owner===o.key);ownerFilter.appendChild(b)});all.classList.toggle('active',owner==='all')}function base(){return sorted.filter(e=>owner==='all'||e.calendarKey===owner)}function text(e){return [e.calendarName||'',e.subject||'',e.location||'',e.organizer||'',e.requiredAttendees||'',e.optionalAttendees||'',e.categories||'',e.bodyPreview||'',e.busyStatus||''].join(' ').toLowerCase()}function filtered(){const q=search.value.trim().toLowerCase();return base().filter(e=>!q||text(e).includes(q))}function byDate(){const m=new Map();filtered().forEach(e=>{if(!m.has(e.date))m.set(e.date,[]);m.get(e.date).push(e)});return m}function cells(){if(view==='week'){const s=startWeek(dObj(selected));return Array.from({length:7},(_,i)=>{const d=addDays(s,i);return{date:ymd(d),inRange:true}})}const first=startMonth(anchor),s=addDays(first,-first.getDay());return Array.from({length:42},(_,i)=>{const d=addDays(s,i);return{date:ymd(d),inRange:d.getMonth()===anchor.getMonth()}})}function updateSummary(){const m=byDate(),te=m.get(todayStr())||[],se=m.get(selected)||[],next=filtered().filter(e=>new Date(e.endISO)>=new Date())[0];document.getElementById('todayCount').textContent=te.length+'件';document.getElementById('todaySub').textContent=te.length?te.map(e=>e.subject).slice(0,2).join(' / '):'予定なし';document.getElementById('selectedCount').textContent=se.length+'件';document.getElementById('selectedSub').textContent=fmtDate(selected);document.getElementById('totalCount').textContent=filtered().length+'件';document.getElementById('nextEvent').textContent=next?next.startHM+' '+next.subject:'なし';document.getElementById('nextEventSub').textContent=next?fmtDate(next.date):'今後の予定なし'}function renderCalendar(){const m=byDate();grid.innerHTML='';layout.classList.toggle('view-week',view==='week');document.getElementById('panelSub').textContent=view==='week'?'週表示':'月表示';rangeLabel.textContent=view==='week'?fmtDate(ymd(startWeek(dObj(selected)))).replace(/曜日|曜/g,'')+' 週':fmtMonth(anchor);cells().forEach(c=>{const items=m.get(c.date)||[],d=dObj(c.date),dow=d.getDay(),h=holidays[c.date],b=node('button','day');if(!c.inRange)b.className+=' other';if(dow===0)b.className+=' sun';if(dow===6)b.className+=' sat';if(h)b.className+=' holiday';if(c.date===todayStr())b.className+=' today';if(c.date===selected)b.className+=' selected';const top=node('div','day-top'),left=node('div','');left.appendChild(node('div','date-main',String(Number(c.date.slice(8,10)))));if(h)left.appendChild(node('span','holiday-name',h));top.appendChild(left);const cnt=node('div','count',items.length?String(items.length):'');if(!items.length)cnt.style.visibility='hidden';top.appendChild(cnt);b.appendChild(top);const list=node('div','mini-list');items.slice(0,view==='week'?8:3).forEach(e=>list.appendChild(node('div','mini'+(e.isPrivate?' private':''),(e.startHM||'')+' '+(e.subject||''))));if(items.length>(view==='week'?8:3))list.appendChild(node('div','more','+'+(items.length-(view==='week'?8:3))+'件'));b.appendChild(list);b.onclick=()=>{selected=c.date;if(view==='month')anchor=startMonth(dObj(selected));renderAll()};grid.appendChild(b)})}function renderAgenda(){const m=byDate(),items=(m.get(selected)||[]).slice().sort((a,b)=>new Date(a.startISO)-new Date(b.startISO));agendaTitle.textContent=fmtDate(selected);agendaSub.textContent=(holidays[selected]?holidays[selected]+' / ':'')+(items.length?items.length+' 件の予定':'予定はありません');agendaList.innerHTML='';if(!items.length){agendaList.appendChild(node('div','empty','この日に表示できる予定はありません。'));return}items.forEach(e=>{const card=node('article','event-card'+(e.isPrivate?' private':''));card.onclick=()=>openDetail(e);const top=node('div','event-top'),left=node('div','');left.appendChild(node('div','event-title',e.subject||'(件名なし)'));const meta=node('div','event-meta');if(e.location)meta.appendChild(node('span','', '📍 '+e.location));if(e.organizer)meta.appendChild(node('span','', '主催: '+e.organizer));left.appendChild(meta);top.appendChild(left);top.appendChild(node('div','event-time',e.allDay?'終日':((e.startHM||'')+(e.endHM?' - '+e.endHM:''))));card.appendChild(top);const chips=node('div','chips');if(e.calendarName)chips.appendChild(node('span','chip owner','👤 '+e.calendarName));if(e.busyStatus)chips.appendChild(node('span','chip',e.busyStatus));if(e.meetingStatus)chips.appendChild(node('span','chip',e.meetingStatus));if(e.allDay)chips.appendChild(node('span','chip','終日'));if(e.isRecurring)chips.appendChild(node('span','chip','繰り返し'));if(e.importance==='高')chips.appendChild(node('span','chip warn','重要度 高'));if(e.attendeeCount)chips.appendChild(node('span','chip','参加者 '+e.attendeeCount+'名'));card.appendChild(chips);agendaList.appendChild(card)})}function openDetail(e){document.getElementById('modalTitle').textContent=e.subject||'(件名なし)';document.getElementById('modalHint').textContent=e.isMasked?'非公開予定のため詳細はマスクされています。':'参加者などの詳細情報';const dateText=fmtDate(e.date)+' '+e.startHM+(e.endHM?' - '+e.endHM:'');const rows=[['予定表',e.calendarName],['予定表メール',e.calendarEmail],['日時',dateText],['所要時間',e.allDay?'終日':e.durationMinutes+'分'],['場所',e.location],['主催者',e.organizer],['必須参加者',e.requiredAttendees],['任意参加者',e.optionalAttendees],['状態',e.busyStatus],['会議状態',e.meetingStatus],['重要度',e.importance],['リマインダー',e.reminder],['分類',e.categories],['本文プレビュー',e.bodyPreview]].filter(r=>r[1]);const dl=node('dl','kv');rows.forEach(r=>{dl.appendChild(node('dt','',r[0]));dl.appendChild(node('dd','',r[1]))});document.getElementById('modalBody').innerHTML='';document.getElementById('modalBody').appendChild(dl);modal.classList.add('on');modalBg.classList.add('on')}function closeModal(){modal.classList.remove('on');modalBg.classList.remove('on')}function renderAll(){updateSummary();renderCalendar();renderAgenda()}document.getElementById('btnMonth').onclick=()=>{view='month';anchor=startMonth(dObj(selected));document.getElementById('btnMonth').classList.add('active');document.getElementById('btnWeek').classList.remove('active');renderAll()};document.getElementById('btnWeek').onclick=()=>{view='week';document.getElementById('btnWeek').classList.add('active');document.getElementById('btnMonth').classList.remove('active');renderAll()};document.getElementById('btnToday').onclick=()=>{selected=todayStr();anchor=startMonth(dObj(selected));renderAll()};document.getElementById('btnClear').onclick=()=>{search.value='';renderAll()};document.getElementById('btnPrint').onclick=()=>window.print();document.getElementById('btnPrev').onclick=()=>{if(view==='week')selected=ymd(addDays(dObj(selected),-7));else anchor=addMonths(anchor,-1);renderAll()};document.getElementById('btnNext').onclick=()=>{if(view==='week')selected=ymd(addDays(dObj(selected),7));else anchor=addMonths(anchor,1);renderAll()};document.getElementById('btnClose').onclick=closeModal;modalBg.onclick=closeModal;document.addEventListener('keydown',e=>{if(e.key==='Escape')closeModal()});search.oninput=()=>renderAll();drawOwners();renderAll();</script></body></html>
'@
    return $template.Replace('__TITLE__',(HtmlEncode $Title)).Replace('__UPDATED__',(HtmlEncode $UpdatedText)).Replace('__DATA__',$DataJson).Replace('__HOLIDAYS__',$HolidayJson)
}
try {
    if(-not (Test-Path -LiteralPath $ConfigPath)){throw "Config file not found: $ConfigPath"}
    $config=Get-Content -LiteralPath $ConfigPath -Raw -Encoding UTF8|ConvertFrom-Json
    $outDir=[string](Get-ConfigValue $config 'OutputDirectory' '.')
    $htmlFileName=[string](Get-ConfigValue $config 'HtmlFileName' 'schedule.html')
    $logFileName=[string](Get-ConfigValue $config 'LogFileName' 'schedule.log')
    $daysAhead=[int](Get-ConfigValue $config 'DaysAhead' 14)
    $title=[string](Get-ConfigValue $config 'Title' 'Outlook Schedule')
    New-Item -ItemType Directory -Force -Path $outDir|Out-Null
    $script:LogPath=Join-Path $outDir $logFileName
    $htmlPath=Join-Path $outDir $htmlFileName
    $tmpHtmlPath=Join-Path $outDir ($htmlFileName+'.tmp')
    $safe2=Join-Path $PSScriptRoot 'Export-OutlookSchedule.Safe2.ps1'
    if(-not (Test-Path -LiteralPath $safe2)){throw "Required exporter not found: $safe2"}
    Write-Log "Run base exporter: $safe2"
    & $safe2 -ConfigPath $ConfigPath
    if($LASTEXITCODE -ne 0){throw "Base exporter failed with exit code $LASTEXITCODE"}
    $baseHtml=Get-Content -LiteralPath $htmlPath -Raw -Encoding UTF8
    $dataJson=Get-ScheduleDataJson -Html $baseHtml
    $rangeStart=(Get-Date).Date
    $rangeEnd=$rangeStart.AddDays($daysAhead+1)
    $holidayJson=ConvertTo-SafeJson (Get-HolidayMap -Config $config -RangeStart $rangeStart -RangeEnd $rangeEnd)
    $html=New-ProHtml -Title $title -UpdatedText (Get-Date -Format 'yyyy/MM/dd HH:mm:ss') -DataJson $dataJson -HolidayJson $holidayJson
    $html|Out-File -FilePath $tmpHtmlPath -Encoding UTF8
    Move-Item -LiteralPath $tmpHtmlPath -Destination $htmlPath -Force
    Write-Log "Wrote Pro UI schedule to $htmlPath"
    exit 0
} catch {
    $line=if($_.InvocationInfo){$_.InvocationInfo.ScriptLineNumber}else{'unknown'}
    Write-Log ("Line {0} : {1}" -f $line,$_.Exception.Message) "ERROR"
    if($_.ScriptStackTrace){Write-Log $_.ScriptStackTrace "ERROR"}
    exit 1
}
